package main

import "fmt"

func solve(grid [][]int64, x int64, y int64, k int64) [][]int64 {
	m := len(grid)
	n := len(grid[0])

	// Create a copy of the grid to avoid modifying the original
	result := make([][]int64, m)
	for i := range result {
		result[i] = make([]int64, n)
		copy(result[i], grid[i])
	}

	// Extract the submatrix
	submatrix := make([][]int64, k)
	for i := 0; i < k; i++ {
		submatrix[i] = make([]int64, n)
		for j := 0; j < n; j++ {
			submatrix[i][j] = grid[x+i][y+j]
		}
	}

	// Reverse the submatrix
	for i := 0; i < k/2; i++ {
		submatrix[i], submatrix[k-1-i] = submatrix[k-1-i], submatrix[i]
	}

	// Put the reversed submatrix back into the result
	for i := 0; i < k; i++ {
		for j := 0; j < n; j++ {
			result[x+i][y+j] = submatrix[i][j]
		}
	}

	return result
}
